void wpr(int x, int y, const wchar_t* str) {
    HANDLE h = GetStdHandle(STD_OUTPUT_HANDLE);
    COORD pos = { (SHORT)x, (SHORT)y };
    SetConsoleCursorPosition(h, pos);

    DWORD written;
    WriteConsoleW(h, str, (DWORD)wcslen(str), &written, NULL);
}

// Convert a narrow std::string to UTF-16, robust to the runtime encoding of
// string literals. Tries strict UTF-8 first; if that fails (e.g. the binary
// was compiled with the system codepage CP949 as execution charset), falls
// back to the ANSI codepage. This makes Korean text render correctly
// regardless of whether /utf-8 was applied at build time.
static std::wstring toWideAuto(const std::string& s) {
    if (s.empty()) return std::wstring();
    // 1. Try strict UTF-8
    int wlen = MultiByteToWideChar(CP_UTF8, MB_ERR_INVALID_CHARS,
        s.c_str(), (int)s.size(), nullptr, 0);
    if (wlen > 0) {
        std::wstring w(wlen, L'\0');
        MultiByteToWideChar(CP_UTF8, MB_ERR_INVALID_CHARS,
            s.c_str(), (int)s.size(), &w[0], wlen);
        return w;
    }
    // 2. Fall back to the system ANSI codepage (CP949 on Korean Windows)
    wlen = MultiByteToWideChar(CP_ACP, 0, s.c_str(), (int)s.size(), nullptr, 0);
    if (wlen > 0) {
        std::wstring w(wlen, L'\0');
        MultiByteToWideChar(CP_ACP, 0, s.c_str(), (int)s.size(), &w[0], wlen);
        return w;
    }
    return std::wstring();
}

// Write a narrow std::string to the console as wide chars (handles Korean).
static void writeConsoleAuto(const std::string& s) {
    if (s.empty()) return;
    std::wstring w = toWideAuto(s);
    if (w.empty()) return;
    HANDLE h = GetStdHandle(STD_OUTPUT_HANDLE);
    DWORD written;
    WriteConsoleW(h, w.c_str(), (DWORD)w.size(), &written, NULL);
}

// 유니코드 출력을 위한 안전한 접근 함수 (필요 시 GameLoop.h에 선언)
void safeWpr(int x, int y, const std::string& line, int charIdx) {
    if (charIdx >= 0 && charIdx < (int)line.length()) {
        // char를 wchar_t로 변환
        std::wstring wStr;
        wStr += (wchar_t)line[charIdx];
        wpr(x, y, wStr.c_str());
    }
    else {
        wpr(x, y, L" "); // 안전하게 공백 출력
    }
}

void showDefeatScreen(int cx, int cy, const std::vector<std::string>& popLines, int selected) {
    // 1. 범위 체크 (오류 방지)
    if (selected < 0 || selected >= (int)popLines.size()) return;

    // 2. 유니코드 설정에 맞게 문자 변환 및 출력
    // popLines[selected][0] 출력
    safeWpr(cx - 19, cy, popLines[selected], 0);

    // popLines[selected][1] 출력
    safeWpr(cx - 19, cy + 1, popLines[selected], 1);
}

static void clearScreen() {
#ifdef _WIN32
    system("cls");
#else
    system("clear");
#endif
}

static void wcout_line(const wchar_t* text) {
    HANDLE h = GetStdHandle(STD_OUTPUT_HANDLE);
    DWORD written;
    WriteConsoleW(h, text, (DWORD)wcslen(text), &written, NULL);
    WriteConsoleW(h, L"\n", 1, &written, NULL);
}

